// AND（かつ）: 両方trueならtrue
// 条件分岐
if (age >= 18 && hasTicket) {
    System.out.println("入場できます");
}

// OR（または）: どちらかtrueならtrue
int day = 6; // 土曜
if (day == 6 || day == 0) {
    System.out.println("休日です");
}

// NOT（否定）: true/falseを反転
boolean isHoliday = false;
if (!isHoliday) {
    System.out.println("平日です");
}

